import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface TideData {
  location: string;
  current: {
    tideLevel: string;
    tideHeight: string;
    time: string;
  };
  highLowTides: {
    type: string;
    time: string;
    height: string;
  }[];
  waveHeight24h: number[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const tideData = response.data as TideData;
  const metaData = response.meta as MetaData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: metaData.theme === 'dark' ? '#1E293B' : '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              {tideData.location}
            </Typography>
            <Typography variant="h4" sx={{ color: metaData.primaryColor, fontWeight: 600 }}>
              {tideData.current.tideLevel} Tide
            </Typography>
            <Typography variant="body2" sx={{ color: metaData.accentColor }}>
              {tideData.current.tideHeight} at {tideData.current.time}
            </Typography>
          </Box>

          <Stack direction="row" spacing={0.5}>
            {tideData.highLowTides.slice(0, 4).map((tide, index) => (
              <Chip
                key={index}
                label={`${tide.type} ${tide.height} @ ${tide.time}`}
                sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: metaData.accentColor, color: '#FFFFFF' }}
              />
            ))}
          </Stack>

          <Box sx={{ width: '100%', height: 120 }}>
            <LineChart
              height={120}
              series={[
                {
                  data: tideData.waveHeight24h,
                  color: metaData.primaryColor,
                  curve: 'natural',
                  showMark: false,
                },
              ]}
              xAxis={[{ data: tideData.waveHeight24h.map((_, i) => i), hide: true }]}
              margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
              sx={{
                '& .MuiLineElement-root': {
                  strokeWidth: 2,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
